import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

/**
 * PulseBoard meta defined inline since this is an extension channel
 * not registered in the core channel order.
 */
const meta = {
  id: "pulseboard" as const,
  label: "PulseBoard",
  selectionLabel: "PulseBoard (Bulletin)",
  docsPath: "/channels/pulseboard",
  docsLabel: "pulseboard",
  blurb: "Real-time bulletin board messaging with boards and direct messages.",
};

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta,
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      defaultAccountId: () => "default",
      resolveAccount: () => ({
        accountId: "default",
        enabled: true,
        configured: false,
      }),
      isConfigured: () => false,
      describeAccount: () => ({ accountId: "default", configured: false }),
    },
    setup: {
      applyAccountConfig: async () => {},
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[${ctx.accountId}] starting PulseBoard provider`);
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

